var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"끈질기군요. 교전을 이렇게 오랫동안 지속해본 상대는 처음입니다.","JPN":"しぶといですね。ここまで交戦を長く続けた相手は初めてです。","ENG":"Persistent, aren't you. I've never fought someone who could keep a battle going this long.","TWN":"真頑強啊，我還是第一次遇到交戰這麼久的對手。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래? 난 너처럼 강한 녀석 몇 번이고 상대해봤거든.","JPN":"そう？　私はあなたみたいな強いやつと戦ったこと、何度もあるけど。","ENG":"Really? I've faced plenty of opponents as strong as you.","TWN":"是嗎？我可是對付過好幾個像你這麼強的對手。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"그렇게 말하는 것치곤 별 진전이 없어 보이는군요. 시간만 끄는 게 목적입니까?","JPN":"それにしてはあまり進展がないようですね。時間稼ぎが狙いですか？","ENG":"For someone who says that, you don't seem to be making much progress. Are you trying to drag this out?","TWN":"話是這麼說，看起來也沒什麼進展呢。你打算拖時間嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"신중한 거라고 해줄래?","JPN":"慎重だと言ってくれる？","ENG":"How about calling it being careful?","TWN":"可以說是謹慎吧？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WHITE","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"연무 때문에 날 놓친 건가?","JPN":"煙霧のせいで私を見逃したのか？","ENG":"Did you lose track of me because of the smoke?","TWN":"是被煙霧影響才失手嗎？"},"stage":{"bg":"WHITE","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뒤를 보고 있는 지금이 기회야.","JPN":"後ろを向いている今がチャンスだ。","ENG":"Now's my chance while you're looking the other way.","TWN":"現在她背對著我，是個好機會。"},"stage":{"bg":"WHITE","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...걸렸군요.","JPN":"……引っかかりましたね。","ENG":"...Got you.","TWN":"……抓到了。"},"stage":{"bg":"WHITE","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"허리가 돌아갔어?!","JPN":"腰が回った！？","ENG":"My waist just twisted?!","TWN":"腰轉過來了！？"},"stage":{"bg":"WHITE","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아차, 이 녀석 인형이었...!","JPN":"そうか、こいつ人形……！","ENG":"Agh. She's also a doll–!","TWN":"糟了，這傢伙是人偶……！"},"stage":{"bg":"WHITE","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_04"},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어라...?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"호라이즌?","JPN":"ホライズン？","ENG":"Horizon?","TWN":"地平線？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"아슬아슬했군요.","JPN":"ギリギリでしたね。","ENG":"That was close.","TWN":"剛剛真驚險。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"하프타임은 끝났습니다.","JPN":"ハーフタイムは終了です。","ENG":"Halftime is over.","TWN":"中場休息結束了。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"어떻게 돌아온 겁니까?","JPN":"どうやって戻ったのですか？","ENG":"How were you able to return?","TWN":"你怎麼回來的？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저도 몰랐던 스폰서의 뒷배가 있더군요. 덕분에 활로를 찾았습니다.","JPN":"私も知らなかったスポンサーがいまして。おかげで活路が見い出せました。","ENG":"Turns out my sponsor had some backing even I didn't know about. Thanks to that, I found a way through.","TWN":"似乎有我不知道的贊助者在背後幫忙。多虧如此，我才找到突破口。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...무슨 헛소린지 모르겠군요.","JPN":"……何のことか分かりませんね。","ENG":"...I have no idea what nonsense you're talking about.","TWN":"……我聽不懂你在說什麼。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"또 방해한다면 이번엔, 추방으로 끝나지 않을 겁니다.","JPN":"また邪魔をするなら、今度は追放程度では済みませんよ。","ENG":"If you interfere again, this time it won't end with exile.","TWN":"如果你再阻礙我們，這次可不只是驅逐這麼簡單。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"누가 봐달라고 했습니까? 지고 나서 자신의 경솔함을 탓하십시오.","JPN":"誰も目を瞑ってくれとは言ってませんが？　負けて己の軽率さを悔いるといいでしょう。","ENG":"Did I ask you to go easy on me? Blame yourself for your recklessness once you lose.","TWN":"誰要你手下留情？輸了之後再去反省自己的輕率吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"낙원을 해치려는 침입자들은... 용납하지 않습니다.","JPN":"楽園に害をなす侵入者は……許しません。","ENG":"Intruders who seek to harm the Promised Land... will not be tolerated.","TWN":"想要破壞樂園的侵入者……絕不容忍。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저 역시 인류의 세계를 지키기 위해서라면 무슨 짓이든 할 겁니다.","JPN":"私も人類の世界を守るためなら、何でもやります。","ENG":"If it's to protect humanity's world, I'll do whatever it takes as well.","TWN":"只要是為了守護人類的世界，我什麼事都做得出來。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"하지만 당신과는 다릅니다. 당신은 명령에 따라 낙원을 지키겠지만, 이건 누군가의 명령이 아닌 제 의지니까요.","JPN":"しかしあなたとは違います。あなたは命令に従って楽園を守っていますが、これは誰かの命令ではなく私の意志ですから。","ENG":"But I'm different from you. You protect the Promised Land because you were ordered to. But this is my own will, not someone else's command.","TWN":"但你和我不同。你是遵從命令守護樂園，而我，是出於自己的意志。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"말장난일 뿐, 같은 말이군요.","JPN":"言葉を飾っているだけで、意味は同じです。","ENG":"Just wordplay. It means the same thing.","TWN":"只是強詞奪理而已，本質還是一樣的。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"아뇨. 전혀 다릅니다.","JPN":"いいえ、まったく違います。","ENG":"No. It's completely different.","TWN":"不，完全不同。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"명령은 철저히 계산된 프로토콜이지만, 의지는 그 무엇에도 얽매이지 않는 변수의 집합이니까요.","JPN":"命令は徹底的に計算されたプロトコルですが、意志は何にも縛られない変数の集合ですから。","ENG":"A command is a thoroughly calculated protocol, but will is a collection of variables bound by nothing.","TWN":"命令是徹底計算過的協議，而意志，則是不受任何束縛的變數集合。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저 황금나무가 타기리온의 옥좌입니다.","JPN":"あの黄金の木がタギリオンの玉座です。","ENG":"That Golden Tree is Thagirion's throne.","TWN":"那棵黃金樹，就是塔基里翁的王座。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"당신은 사람들과 함께 먼저 가십시오, 유미나.","JPN":"あなたは他の皆さんと先に行ってください。ヤナギ・ミナ。","ENG":"Go ahead with the others first, Mina.","TWN":"你們先和其他人一起離開吧，劉米娜。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...알겠어.","JPN":"……分かった。","ENG":"...All right.","TWN":"……我知道了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"조심해, 호라이즌.","JPN":"気をつけて、ホライズン。","ENG":"Be careful, Horizon.","TWN":"小心點，地平線。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"지금, 누구 마음대로...!","JPN":"何を勝手に……！","ENG":"Now, who gave you permission to–!","TWN":"現在，誰准你……！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_HORIZON_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"...좌표 개방. 지금입니다.","JPN":"……座標開放。今です。","ENG":"...Opening coordinates. Now.","TWN":"……座標開啟。就是現在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};